import{_ as a,o as i,c as r,a2 as t}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Archiving","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/archiving.md","filePath":"en/guide/archiving.md"}'),n={name:"en/guide/archiving.md"};function s(o,e,l,h,c,d){return i(),r("div",null,[...e[0]||(e[0]=[t(`<h1 id="archiving" tabindex="-1">Archiving <a class="header-anchor" href="#archiving" aria-label="Permalink to &quot;Archiving&quot;">​</a></h1><p>Nid allows you to save your emails to your NAS in <strong>EML</strong> format (one file per email). Archives are indexed in PostgreSQL for fast searching.</p><hr><h2 id="why-archive" tabindex="-1">Why archive? <a class="header-anchor" href="#why-archive" aria-label="Permalink to &quot;Why archive?&quot;">​</a></h2><ul><li><strong>Free up your Gmail quota</strong>: delete emails from Gmail after archiving them locally</li><li><strong>Long-term backup</strong>: EML files are in a standard format, readable by any email client (Thunderbird, Outlook, etc.)</li><li><strong>Fast search</strong>: archives are full-text indexed in PostgreSQL</li><li><strong>Your data stays with you</strong>: no data leaves your network</li></ul><hr><h2 id="archiving-emails" tabindex="-1">Archiving emails <a class="header-anchor" href="#archiving-emails" aria-label="Permalink to &quot;Archiving emails&quot;">​</a></h2><h3 id="archiving-by-selection" tabindex="-1">Archiving by selection <a class="header-anchor" href="#archiving-by-selection" aria-label="Permalink to &quot;Archiving by selection&quot;">​</a></h3><ol><li>In <strong>My emails</strong>, select the emails to archive</li><li>Click <strong>Archive to NAS</strong> in the action bar</li><li>An archiving job is created with real-time tracking</li></ol><h3 id="archiving-by-query-archive-all" tabindex="-1">Archiving by query (archive all) <a class="header-anchor" href="#archiving-by-query-archive-all" aria-label="Permalink to &quot;Archiving by query (archive all)&quot;">​</a></h3><ol><li>In <strong>My emails</strong>, enter a search query (e.g. <code>from:amazon.fr older_than:6m</code>)</li><li>Click <strong>Archive all</strong></li><li>All matching emails are archived differentially</li></ol><h3 id="differential-archiving" tabindex="-1">Differential archiving <a class="header-anchor" href="#differential-archiving" aria-label="Permalink to &quot;Differential archiving&quot;">​</a></h3><p>Archiving is <strong>differential</strong> by default: only emails that have not yet been archived are processed. If you archive the same query twice, the second run only processes new emails.</p><blockquote><p>📸 <em>Suggested screenshot: &quot;Archive all&quot; button on the My emails page</em></p></blockquote><hr><h2 id="browsing-archives" tabindex="-1">Browsing archives <a class="header-anchor" href="#browsing-archives" aria-label="Permalink to &quot;Browsing archives&quot;">​</a></h2><p>The <strong>Archives</strong> page in the sidebar displays all your archived emails.</p><h3 id="full-text-search" tabindex="-1">Full-text search <a class="header-anchor" href="#full-text-search" aria-label="Permalink to &quot;Full-text search&quot;">​</a></h3><p>The search bar enables <strong>full-text search</strong> across your archives. The search covers:</p><ul><li><strong>Email subject</strong> (highest priority)</li><li><strong>Sender</strong> (medium priority)</li><li><strong>Content</strong> of the email (excerpt/snippet, lowest priority)</li></ul><blockquote><p>📸 <em>Suggested screenshot: Archives page with the full-text search bar and results</em></p></blockquote><h3 id="sorting-and-filters" tabindex="-1">Sorting and filters <a class="header-anchor" href="#sorting-and-filters" aria-label="Permalink to &quot;Sorting and filters&quot;">​</a></h3><p>You can sort archives by:</p><ul><li>Date (newest / oldest)</li><li>Size (largest / smallest)</li><li>Sender</li></ul><h3 id="reading-an-archived-email" tabindex="-1">Reading an archived email <a class="header-anchor" href="#reading-an-archived-email" aria-label="Permalink to &quot;Reading an archived email&quot;">​</a></h3><p>Click on an archived email to open it in the built-in reader. The content is read directly from the EML file on disk.</p><p>If the email is <strong>encrypted</strong>, it will be decrypted on the fly (you must have configured your passphrase — see <a href="./privacy.html#chiffrement-des-archives">Privacy</a>).</p><h3 id="conversation-thread-view" tabindex="-1">Conversation (thread) view <a class="header-anchor" href="#conversation-thread-view" aria-label="Permalink to &quot;Conversation (thread) view&quot;">​</a></h3><p>Archives support the <strong>conversation</strong> view: emails sharing the same thread are grouped together. Switch between list view and conversation view with the toggle at the top of the page.</p><blockquote><p>📸 <em>Suggested screenshot: list/conversation toggle on the Archives page</em></p></blockquote><hr><h2 id="archived-attachments" tabindex="-1">Archived attachments <a class="header-anchor" href="#archived-attachments" aria-label="Permalink to &quot;Archived attachments&quot;">​</a></h2><p>Attachments are extracted and stored separately during archiving. You can download them individually from:</p><ul><li>The archived email reader</li><li>The <strong>Attachments</strong> page (Archives tab)</li></ul><hr><h2 id="zip-export" tabindex="-1">ZIP export <a class="header-anchor" href="#zip-export" aria-label="Permalink to &quot;ZIP export&quot;">​</a></h2><p>Export a selection of archived emails in ZIP format:</p><ol><li>In <strong>Archives</strong>, select the emails to export</li><li>Click <strong>Export as ZIP</strong></li><li>A ZIP file containing the EML files is downloaded</li></ol><hr><h2 id="disk-organization" tabindex="-1">Disk organization <a class="header-anchor" href="#disk-organization" aria-label="Permalink to &quot;Disk organization&quot;">​</a></h2><p>Archives are organized on the NAS according to the following structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/archives/</span></span>
<span class="line"><span>└── {account_id}/</span></span>
<span class="line"><span>    └── {year}/</span></span>
<span class="line"><span>        └── {month}/</span></span>
<span class="line"><span>            ├── {message_id}.eml</span></span>
<span class="line"><span>            └── attachments/</span></span>
<span class="line"><span>                ├── invoice.pdf</span></span>
<span class="line"><span>                └── photo.jpg</span></span></code></pre></div><p>Each email is identified by a unique UUID (the <code>gmail_message_id</code>).</p>`,43)])])}const u=a(n,[["render",s]]);export{p as __pageData,u as default};
